function formatNumber(num, a, b, c) {
    let str = num.toString();
    let result = [];
    let lastPos = 0;

    function processSegment(segment) {
        if (segment.length > 1) {
            let processed = segment.replace(/^0+/, '');
            return processed === '' ? '0' : processed;
        }
        return segment;
    }

    if (a !== undefined) {
        let segment = str.slice(lastPos, a);
        result.push(processSegment(segment));
        lastPos = a;
    }

    if (b !== undefined) {
        let segment = str.slice(lastPos, b);
        result.push(processSegment(segment));
        lastPos = b;
    }

    if (c !== undefined) {
        let segment = str.slice(lastPos, c);
        result.push(processSegment(segment));
        lastPos = c;
    }

    if (lastPos < str.length) {
        let segment = str.slice(lastPos);
        result.push(processSegment(segment));
    }

    return result.join('.');
}

