// ============= 请求链接函数 =============

function xGod(type, path, params, body, ck, hd) {
    const { java, cache, source, cookie } = this;

    let Type = type.replace(/ok|bd|\d+/g,'');
    if (!this.Get(Type) || this.Get(Type) == '' || Date.now() - parseInt(this.Get(Type).time || '0') > 30 * 24 * 60 * 60 * 1000) this.device_register(Type, true);
    let device = this.Get(Type);
    let Code = type.match(/(\d+)/) ? type.match(/(\d+)/)[1] : null;
    if (Code) {
        device.version = Code;
        device.version_str = formatNumber(Code, 1, 2, 3);
    }
    let host = /API/.test(type) ? 'https://reading.snssdk.com' : 'https://novel.snssdk.com';
    let fullUrl = (/http/.test(path) ? '' : host) + path + (params ? params : '');
    let paramsObj = {};
    if (typeof params === 'string' && params) {
        params.split('&').forEach(pair => {
            let [key, value] = pair.split('=');
            if (key) paramsObj[key] = value ? decodeURIComponent(value) : '';
        });
    }

    let signResult = JSON.parse(java.ajax(sixgodHost + '/api/sign,' + JSON.stringify({
        "headers": {"Content-Type": "application/json"},
        "body": {
            "user": sixgodUser,
            "auth": sixgodAuth,
            "url": fullUrl,
            "params": paramsObj,
            "device": device,
            "body": body,
            "cookie": ck,
            "header": hd
        },
        "method": "POST"
    }))).data;

    if (/ok/.test(type)) {
        //java.log(JSON.stringify(signResult));
        if (signResult.options.body) {
            let contentType = signResult.options.headers ? signResult.options.headers["content-type"] : '';
            let bodyType = signResult.options.headers ? signResult.options.headers["x-body-type"] : '';

            if (contentType === "application/octet-stream" || bodyType === "base64-binary") {
                return okhttpPost(signResult.url, java.base64DecodeToByteArray(signResult.options.body), signResult.options.headers);
            } else {
                return okhttpPost(signResult.url, signResult.options.body, signResult.options.headers);
            }
        } else {
            return okhttpGet(signResult.url, signResult.options.headers);
        }
    }

    let requestOption = {
        "headers": signResult.options.headers,
        "method": signResult.options.method
    };
    if (signResult.options.body) requestOption.body = signResult.options.body;

    return signResult.url + ',' + JSON.stringify(requestOption);
}




