<body>
    <div id="loading" class="loading">
        <div class="loader-basic"></div>
    </div>

    <div class="header">
        <h3 id="h3"></h3>
    </div>

    <div class="content">
        <ul id="viewer" class="comments-list"></ul>
    </div>$2

    <button id="upload-comment-btn" class="upload-comment-btn" title="上传评论">
        <span class="tooltip">上传评论</span>
    </button>

    <div id="upload-comment-dialog" class="upload-comment-dialog">
        <div class="upload-comment-content">
            <div class="upload-comment-header">
                <h3>发表评论</h3>
            </div>
            <textarea 
                id="upload-comment-text" 
                class="upload-comment-textarea" 
                placeholder="请输入您的评论内容..."
                maxlength="1000"
                rows="5"
            ></textarea>
            <div class="upload-comment-footer">
                <button id="upload-comment-cancel" class="upload-comment-cancel">取消</button>
                <button id="upload-comment-submit" class="upload-comment-submit">提交评论</button>
            </div>
        </div>
    </div>

    <script>
        let viewer;
        let isLoading = false;
        let ck = '${cache.get('fqck') || ''}';

        function showCommentDialog() {
            if (!/sessionid/.test(ck)) {
                showAlert('未登录账号', 'error');
                return;
            }
            const dialog = document.getElementById('upload-comment-dialog');
            const textarea = document.getElementById('upload-comment-text');

            dialog.classList.add('active');
            document.body.style.overflow = 'hidden';

            setTimeout(() => {
                textarea.focus();
            }, 100);
        }

        function hideCommentDialog() {
            const dialog = document.getElementById('upload-comment-dialog');
            const textarea = document.getElementById('upload-comment-text');

            dialog.classList.remove('active');
            document.body.style.overflow = '';
            textarea.value = '';
        }

        function uploadComment() {
            const submitBtn = document.getElementById('upload-comment-submit');
            const textarea = document.getElementById('upload-comment-text');
            const commentText = textarea.value.trim();

            if (!commentText) {
                showAlert('请输入评论内容', 'error');
                textarea.focus();
                return;
            }

            if (commentText.length > 1000) {
                showAlert('评论内容不能超过1000个字符', 'error');
                return;
            }

            submitBtn.disabled = true;

            const paramsElement = document.getElementById('params');
            const type = parseInt(paramsElement.dataset.type);
            const params = paramsElement.textContent;
            const cleanParams = params.replace(/'/g, '').replace(/\s/g, '');
            const paramArray = cleanParams.split(',');
            const bookId = paramArray[0];
            const chapterId = paramArray[1];
            const author = paramArray[2];

            try {
                let runCommand;

                if (type === 2) {
                    const relativeId = document.querySelector('.count').dataset.id;
                    runCommand = \`putChapterReview('\${bookId}', '\${chapterId}', '\${author}', '\${relativeId}', '\${commentText}', '\${ck}')\`;
                } else {
                    const para_content = document.getElementById('paracontent').textContent;
                    const paragraphId = paramArray[3];
                    runCommand = \`putParagraphsReview('\${bookId}', '\${chapterId}', '\${author}', \${paragraphId}, '1', '\${para_content}', '\${commentText}', '\${ck}')\`;
                }

                window.run(runCommand)
                    .then(resultString => {
                        submitBtn.disabled = false;

                        if (!resultString || resultString.trim() === '') {
                            showAlert('上传失败：返回结果为空', 'error');
                            return;
                        }

                        if (resultString.includes('comment-item')) {
                            hideCommentDialog();
                            addCommentToTop(resultString);
                            showAlert('评论发布成功！', 'success');
                            setTimeout(() => {
                                if (viewer) {
                                    viewer.update();
                                }
                            }, 100);
                        } else {
                            showAlert('上传失败：' + resultString, 'error');
                        }
                    }).catch(error => {
                        submitBtn.disabled = false;
                        submitBtn.classList.remove('loading');
                        showAlert('上传失败：' + (error.message || '网络错误或服务不可用'), 'error');
                    });

            } catch (error) {
                console.error('上传初始化失败:', error);
                submitBtn.disabled = false;
                submitBtn.classList.remove('loading');
                showAlert('上传初始化失败：' + (error.message || '未知错误'), 'error');
            }
        }

        function addCommentToTop(commentHtml) {
            const commentsList = document.getElementById('viewer');
            if (!commentsList) return;

            const tempDiv = document.createElement('div');
            tempDiv.innerHTML = commentHtml;
            const newComment = tempDiv.firstElementChild;

            if (newComment) {
                const existingComments = commentsList.querySelectorAll('.comment-item');
                const noCommentItem = commentsList.querySelector('.comment-item[style*="text-align: center"]');

                if (existingComments.length > 0 && !noCommentItem) {
                    commentsList.insertBefore(newComment, existingComments[0]);
                } else {
                    commentsList.appendChild(newComment);

                    if (noCommentItem) {
                        noCommentItem.remove();
                    }
                }

                updateCommentCount();

                newComment.style.opacity = '0';
                newComment.style.transform = 'translateY(-20px)';
                newComment.style.transition = 'all 0.3s ease';

                setTimeout(() => {
                    newComment.style.opacity = '1';
                    newComment.style.transform = 'translateY(0)';
                }, 10);
            }
        }

        function updateCommentCount() {
            const countElement = document.querySelector('.header h3 .count');
            const originalText = countElement.textContent;
            const match = originalText.match(/共\\s*(\\d+)\\s*条/);
            const oldCount = parseInt(match[1]);
            const newCount = oldCount + 1;
            countElement.textContent = countElement.textContent.replace(
                /共\\s*(\\d+)\\s*条/, 
                \`共 \${newCount} 条\`
            );
        }

        function showAlert(message, type) {
            const existingAlert = document.querySelector('.custom-alert');
            if (existingAlert) {
                existingAlert.remove();
            }

            const alertDiv = document.createElement('div');
            alertDiv.className = \`custom-alert alert-\${type}\`;

            const styles = {
                position: 'fixed',
                top: '20px',
                right: '20px',
                padding: '12px 20px',
                borderRadius: '8px',
                zIndex: '2000',
                maxWidth: '480px',
                boxShadow: '0 4px 12px rgba(0, 0, 0, 0.15)',
                animation: 'slideIn 0.3s ease',
                display: 'flex',
                alignItems: 'center',
                gap: '10px',
                fontSize: '14px'
            };

            if (type === 'success') {
                styles.backgroundColor = 'var(--primary-color)';
                styles.color = 'white';
                styles.borderLeft = '4px solid #34c759';
            } else {
                styles.backgroundColor = 'var(--bg-card)';
                styles.color = 'var(--text-primary)';
                styles.borderLeft = '4px solid #ff3b30';
            }

            Object.assign(alertDiv.style, styles);

            const icon = document.createElement('span');
            icon.innerHTML = type === 'success' ? '✔' : '❌';
            icon.style.fontSize = '16px';
            icon.style.fontWeight = 'bold';

            const text = document.createElement('span');
            text.textContent = message;
            text.style.flex = '1';

            const closeBtn = document.createElement('button');
            closeBtn.innerHTML = '×';
            closeBtn.style.cssText = \`
                background: none;
                border: none;
                color: inherit;
                font-size: 18px;
                cursor: pointer;
                padding: 0;
                width: 24px;
                height: 24px;
                display: flex;
                align-items: center;
                justify-content: center;
                opacity: 0.7;
                margin-left: 5px;
            \`;
            closeBtn.onclick = () => alertDiv.remove();

            alertDiv.appendChild(icon);
            alertDiv.appendChild(text);
            alertDiv.appendChild(closeBtn);

            document.body.appendChild(alertDiv);

            setTimeout(() => {
                if (alertDiv.parentNode) {
                    alertDiv.style.animation = 'slideOut 0.3s ease';
                    setTimeout(() => alertDiv.remove(), 300);
                }
            }, 5000);
        }

        function initUploadButton() {
            const uploadBtn = document.getElementById('upload-comment-btn');
            if (!uploadBtn) return;

            const paramsElement = document.getElementById('params');
            const type = parseInt(paramsElement.dataset.type);

            uploadBtn.addEventListener('click', showCommentDialog);

            const tooltip = uploadBtn.querySelector('.tooltip');
            const uploadtitle = document.querySelector('.upload-comment-header h3');
            if (tooltip) {
                if (type === 2) {
                    tooltip.textContent = '发表章节评论';
                    uploadtitle.textContent = '发表章节评论';
                    uploadBtn.title = '发表章节评论';
                } else {
                    tooltip.textContent = '发表段落评论';
                    uploadtitle.textContent = '发表段落评论';
                    uploadBtn.title = '发表段落评论';
                }
            }

            const cancelBtn = document.getElementById('upload-comment-cancel');
            const submitBtn = document.getElementById('upload-comment-submit');

            if (cancelBtn) {
                cancelBtn.addEventListener('click', hideCommentDialog);
            }

            if (submitBtn) {
                submitBtn.addEventListener('click', uploadComment);
            }

            const dialog = document.getElementById('upload-comment-dialog');
            if (dialog) {
                dialog.addEventListener('click', (e) => {
                    if (e.target === dialog) {
                        hideCommentDialog();
                    }
                });
            }

            const textarea = document.getElementById('upload-comment-text');
            if (textarea) {
                textarea.addEventListener('keydown', (e) => {
                    if (e.ctrlKey && e.key === 'Enter') {
                        e.preventDefault();
                        uploadComment();
                    }
                });
            }
        }

        const initFullscreenScrollHandler = () => {
            let isFullscreen = false;

            const handleFullscreenChange = () => {
                const isCurrentlyFullscreen = document.fullscreenElement || 
                                            document.webkitFullscreenElement || 
                                            document.mozFullScreenElement || 
                                            document.msFullscreenElement;

                if (isCurrentlyFullscreen && !isFullscreen) {
                    isFullscreen = true;
                    document.body.classList.add('no-scroll');

                    const fullscreenElement = document.fullscreenElement || 
                                            document.webkitFullscreenElement || 
                                            document.mozFullScreenElement || 
                                            document.msFullscreenElement;

                    if (fullscreenElement && fullscreenElement.classList.contains('comment-video')) {
                        fullscreenElement.classList.add('video-fullscreen');
                        fullscreenElement.style.border = 'none';
                        fullscreenElement.style.outline = 'none';
                    }
                } else if (!isCurrentlyFullscreen && isFullscreen) {
                    isFullscreen = false;
                    document.body.classList.remove('no-scroll');

                    const videos = document.querySelectorAll('.comment-video.video-fullscreen');
                    videos.forEach(video => {
                        video.classList.remove('video-fullscreen');
                        video.style.border = '';
                        video.style.outline = '';
                    });
                }
            };

            document.addEventListener('fullscreenchange', handleFullscreenChange);
            document.addEventListener('webkitfullscreenchange', handleFullscreenChange);
            document.addEventListener('mozfullscreenchange', handleFullscreenChange);
            document.addEventListener('MSFullscreenChange', handleFullscreenChange);

            return;
        };

        const scrollHandler = initFullscreenScrollHandler();

        function calculateScale(element) {
            const width = element.clientWidth || element.offsetWidth;
            const height = element.clientHeight || element.offsetHeight;
            const maxDimension = Math.max(width, height);

            if (maxDimension <= 150) {
                return 1.03; 
            } else if (maxDimension <= 300) {
                return 1.02;
            } else {
                return 1.01;
            }
        }

        function initMediaHoverEffects() {
            const mediaElements = document.querySelectorAll('.comment-image, .comment-video');

            mediaElements.forEach(media => {
                const isFullscreen = document.fullscreenElement === media || 
                                   document.webkitFullscreenElement === media ||
                                   document.mozFullScreenElement === media ||
                                   document.msFullscreenElement === media;

                if (isFullscreen) {
                    media.style.transform = 'none';
                    return;
                }

                media.addEventListener('mouseenter', function() {
                    const isCurrentlyFullscreen = document.fullscreenElement === this || 
                                                document.webkitFullscreenElement === this ||
                                                document.mozFullScreenElement === this ||
                                                document.msFullscreenElement === this;

                    if (isCurrentlyFullscreen) return;

                    const scale = calculateScale(this);
                    this.style.transform = \`scale(\${scale})\`;
                    this.style.zIndex = '10';
                    this.style.position = 'relative';
                });

                media.addEventListener('mouseleave', function() {
                    const isCurrentlyFullscreen = document.fullscreenElement === this || 
                                                document.webkitFullscreenElement === this ||
                                                document.mozFullScreenElement === this ||
                                                document.msFullscreenElement === this;

                    if (isCurrentlyFullscreen) return;

                    this.style.transform = 'scale(1)';
                    this.style.zIndex = '';
                    this.style.position = '';
                });

                if (!media.style.transition) {
                    media.style.transition = 'all 0.3s ease';
                }
            });
        }

        function initMediaObserver() {
            const observer = new MutationObserver((mutations) => {
                let shouldInit = false;

                mutations.forEach((mutation) => {
                    if (mutation.type === 'childList' && mutation.addedNodes.length > 0) {
                        mutation.addedNodes.forEach((node) => {
                            if (node.nodeType === 1) {
                                if (node.matches && (node.matches('.comment-image, .comment-video') || 
                                    node.querySelector('.comment-image, .comment-video'))) {
                                    shouldInit = true;
                                }
                            }
                        });
                    }
                });

                if (shouldInit) {
                    setTimeout(initMediaHoverEffects, 100);
                }
            });

            observer.observe(document.getElementById('viewer'), {
                childList: true,
                subtree: true
            });
        }

        function ininImgViewer() {
            if (!viewer) {
                viewer = new Viewer(document.getElementById('viewer'), {
                    url: 'data-original',
                    navbar: false,
                    title: false,
                    toolbar: {
                        zoomIn: true,
                        zoomOut: true,
                        oneToOne: true,
                        reset: true,
                        rotateLeft: true,
                        rotateRight: true,
                        flipHorizontal: true,
                        flipVertical: true,
                    },
                    backdrop: true,
                    loading: true,
                    loop: true
                });
            } else {
                viewer.update();
            }

            setTimeout(initMediaHoverEffects, 50);
        }

        function nextPage(element) {
            if (!element || isLoading) return;

            isLoading = true;
            element.classList.add('is_loading');
            updateView(element.dataset.params, element.dataset.type);
        }

        function moreReply(element) {
            if (!element) return;

            const params = element.dataset.params;
            const type = parseInt(element.dataset.type);
            element.classList.add('hidden');

            const loadingDiv = document.createElement('div');
            loadingDiv.className = 'loader-more';
            loadingDiv.innerHTML = '<div class="loader-basic"></div>';
            element.parentNode.appendChild(loadingDiv);

            const functionName = type == 3 ? "getChapterReplyByPage_3" : type == 4 ? "getChapterReplyByPage_4" : "getParagraphsReplyByPage";
            window.run(functionName + "(" + params + ")")
                .then(result => {
                    const template = document.createElement('template');
                    template.innerHTML = result;
                    element.parentNode.insertBefore(template.content, loadingDiv.nextSibling);
                    element.remove();
                    loadingDiv.remove();
                    ininImgViewer();
                })
                .catch(error => {
                    console.error('加载回复失败:', error);
                    loadingDiv.remove();
                    element.classList.remove('hidden');
                });
        }

        function moreNestedReply(element) {
            if (!element) return;

            const params = element.dataset.params;
            const type = parseInt(element.dataset.type); // 3表示三级回复，4表示四级回复
            element.classList.add('hidden');

            const loadingDiv = document.createElement('div');
            loadingDiv.className = 'loader-more';
            loadingDiv.innerHTML = '<div class="loader-basic"></div>';
            element.parentNode.appendChild(loadingDiv);

            window.run("getChapterNestedReplyByPage(" + params + ")")
                .then(result => {
                    if (result && result.trim()) {
                        const template = document.createElement('template');
                        template.innerHTML = result;

                        const nestedContainer = document.createElement('ul');
                        nestedContainer.className = 'nested-replies-list';

                        const level = type - 2; // type=3 => level=1, type=4 => level=2
                        nestedContainer.classList.add(\`level-\${Math.min(level, 3)}\`);

                        nestedContainer.appendChild(template.content);
                        element.parentNode.appendChild(nestedContainer);
                    }

                    loadingDiv.remove();

                    if (result && result.trim()) {
                        element.remove();
                    } else {
                        element.classList.remove('hidden');
                    }

                    ininImgViewer();
                })
                .catch(error => {
                    console.error('加载嵌套回复失败:', error);
                    loadingDiv.remove();
                    element.classList.remove('hidden');
                });
        }

        function updateView(params, type) {
            const element = document.getElementById('next_page');

            const functionName = type == 2 ? "getChapterReviewByPage" : "getParagraphsReviewByPage";

            window.run(functionName + "(" + params + ")")
                .then(result => {
                    try {
                        result = JSON.parse(result);
                        const template = document.createElement('template');
                        template.innerHTML = result.html;

                        const viewerElement = document.getElementById('viewer');
                        if (element) {
                            viewerElement.insertBefore(template.content, element);
                        } else {
                            viewerElement.appendChild(template.content);
                        }

                        if (result.paraContent) {
                            const pt = document.getElementById('paracontent');
                            pt.textContent = result.paraContent;
                        }

                        if (result.refferContent) {
                            const ct = document.getElementById('count');
                            ct.outerHTML = result.refferContent;
                        }

                        document.getElementById('loading').classList.add('hidden');

                        if (element) {
                            element.remove();
                        }

                        ininImgViewer();
                        isLoading = false;
                    } catch (e) {
                        console.error('解析结果失败:', e);
                        isLoading = false;
                        if (element) {
                            element.classList.remove('is_loading');
                        }
                    }
                })
                .catch(error => {
                    console.error('加载评论失败:', error);
                    isLoading = false;
                    if (element) {
                        element.classList.remove('is_loading');
                        element.remove();
                    }
                });
        }

        function createNode(html) {
            const template = document.createElement('template');
            template.innerHTML = html;
            return template.content;
        }

        function debounce(func, delay) {
            let timeout;
            return function (...args) {
                clearTimeout(timeout);
                timeout = setTimeout(() => func.apply(this, args), delay);
            };
        }

        document.addEventListener('DOMContentLoaded', function() {
            initUploadButton();

            const paramsElement = document.getElementById('params');
            if (paramsElement) {
                const params = paramsElement.textContent;
                const type = parseInt(paramsElement.dataset.type);

                updateView(params, type);
            }
        });

        document.addEventListener('wheel', function(e) {
            const content = e.target.closest('.header h3 .content');
            if (content && content.scrollHeight > content.clientHeight) {
                e.stopPropagation();
            }
        }, { capture: true });

        window.addEventListener('scroll', debounce(() => {
            if (isLoading) return;

            const scrollTop = window.pageYOffset || document.documentElement.scrollTop;
            const viewportHeight = window.innerHeight;
            const documentHeight = document.documentElement.scrollHeight;

            if (scrollTop + viewportHeight >= documentHeight - 2000) {
                const element = document.getElementById('next_page');
                if (element) {
                    nextPage(element);
                }
            }
        }, 150));

        document.addEventListener('click', (e) => {
            if (e.target.classList.contains('comment-image') && viewer) {
                viewer.show();
            }
        });

        window.addEventListener('load', () => {
            setTimeout(() => {
                initMediaObserver();
            }, 10);
        });

        (function scrollOnHover() {
            setInterval(() => {
                const scrollY = window.pageYOffset || document.documentElement.scrollTop;
                const hasUploadActive = document.querySelector('.upload-comment-dialog').matches('.active');
                const hasImageHovered = Array.from(document.querySelectorAll('.comment-image')).some(a => a.matches(':hover'));
                const hasHeaderHovered = document.querySelector('.header').matches(':hover');
                const isCurrentlyFullscreen = document.fullscreenElement || 
                                            document.webkitFullscreenElement || 
                                            document.mozFullScreenElement || 
                                            document.msFullscreenElement;

                if (hasUploadActive || hasImageHovered || hasHeaderHovered) {
                    if (scrollY === 0) window.scrollTo(0, 1);
                } else if (isCurrentlyFullscreen) {
                    java.upConfig(\`{
                        "backgroundDimAmount":1,
                        "heightPercentage": 1
                    }\`);
                } else {
                    java.upConfig(\`{
                        "backgroundDimAmount":0.7,
                        "heightPercentage": 0.9
                    }\`);
                }
            }, 10);
        })();
    </script>
</body>
</html>`;

    return String(reviewHtmlTemplate);
}

function putParagraphsReview(bookId, chapterId, author, paragraphId, version, para_content, text, ck) {
    const { java, cache } = this;

    const body = {
        "business_param": {
            "book_id": bookId,
            "has_aigc_content": false,
            "ignore_urge_rule": false,
            "is_confirm_request": false,
            "item_version": version,
            "log_extra": {},
            "para_content": para_content,
            "pos": {
                "end_container_index": paragraphId,
                "end_element_index": 0,
                "end_element_offset": (para_content.length + 1),
                "start_container_index": paragraphId,
                "start_element_index": 0,
                "start_element_offset": 0
            },
            "pos_v1": {
                "end_media_index": 0,
                "end_para_index": paragraphId,
                "end_word_pos": para_content.length,
                "start_media_index": 0,
                "start_para_index": paragraphId,
                "start_word_pos": 0
            },
            "read_item_cnt": 0,
            "score": 0,
