        "count": count,
        "group_id": chapterId,
        "group_type": 15,
        "sort": 1,
        "cursor": String(cursor)
    };

    const result = JSON.parse(java.ajax(this.xGod(
        "API669",
        `/novel/commentapi/comment/list/${chapterId}/v1?`,
        "",
        JSON.stringify(body),
        ck
    )));
    let html = "";
    let refferContent = "";
    const comments = result.data?.data_list || [];

    if (comments.length > 0) {
        if (page === 0) {
            const paraContent = comments[0]?.comment?.expand?.para_src_content || "";
            refferContent = `
                <span class="count" id="count">共 ${result.data?.common_list_info?.total || 0} 条</span>
            `;
        }

        const getImagesHtml = (imageDataList) => 
            imageDataList?.image_data?.filter(i => i?.web_uri?.trim())
                .map(i => `<img class="comment-image" data-original="${i.web_uri}" src="${i.web_uri}" alt="评论图片" loading="lazy" style="height:120px;width:auto;">`)
                .join('') || '';

        const getVideosHtml = (videoInfo) => {
            if (!videoInfo?.video_model) return '';

            try {
                const videoModel = JSON.parse(videoInfo.video_model);
                const videoList = videoModel.video_list;

                if (!videoList || Object.keys(videoList).length === 0) return '';

                const firstVideoKey = Object.keys(videoList)[0];
                const videoData = videoList[firstVideoKey];

                if (!videoData?.main_url) return '';

                const videoUrl = java.base64Decode(videoData.main_url);
                const posterUrl = videoInfo.first_frame_poster || videoModel.poster_url || '';

                return `
                <div class="comment-videos">
                    <div class="video-container">
                        <video class="comment-video" preload="metadata" playsinline webkit-playsinline poster="${posterUrl}" controls style="width: 100%; max-height: 400px; border-radius: 6px;">
                            <source src="${videoUrl}" type="video/mp4">
                        </video>
                    </div>
                </div>`;
            } catch (e) {
                java.log('解析视频信息失败:' + e);
                return '';
            }
        };

        comments.forEach((item, index) => {
            const { comment } = item;
            const { user_action } = comment;
            const { user_info, content, create_timestamp } = comment?.common || {};
            const { digg_count, reply_count } = comment?.stat || {};
            const floor = cursor + index + 1;

            const userAvatar = user_info?.base_info?.user_avatar || '';
            const userName = user_info?.base_info?.user_name || '匿名用户';

            let userBadges = '';
            if (user_info) {
                const gender = user_info.base_info?.gender;
                const is_vip = user_info.user_tag?.is_vip;
                const is_author = user_info.user_tag?.is_author;

                if (gender === 1) {
                    userBadges = '<span class="user-badges"><span class="user-badge gender-male"></span>';
                } else if (gender === 0) {
                    userBadges = '<span class="user-badges"><span class="user-badge gender-female"></span>';
                } else {
                    userBadges = '<span class="user-badges"><span class="user-badge gender-unknown"></span>';
                }

                if (is_vip) {
                    userBadges += '<span class="user-badge vip"></span>';
                }

                if (is_author) {
                    userBadges += '<span class="user-badge author"></span>';
                }

                userBadges += '</span>';
            }

            let userTagHtml = '';

            const userTagUrl = user_info?.user_tag?.sticker?.sticker?.url;
            if (userTagUrl) {
                userTagHtml += `<img class="user-tag" src="${userTagUrl}" alt="用户标签">`;
            }

            if (userName == java.base64Decode(author)) {
                let bgColor = 'var(--text-tertiary)';
                let textColor = 'var(--bg-card)';

                userTagHtml += `
                <span class="user-title-tag" 
                    style="background-color: ${bgColor}; 
                    color: ${textColor};">
                    作者
                </span>`;
            }

            if (user_action.author_digg_time) {
                let bgColor = 'var(--text-tertiary)';
                let textColor = 'var(--bg-card)';

                userTagHtml += `
                <span class="user-title-tag" 
                    style="background-color: ${bgColor}; 
                    color: ${textColor};">
                    作者赞过
                </span>`;
            }

            if (user_info?.user_tag?.user_title_info?.[0]?.label) {
                try {
                    const label = user_info.user_tag.user_title_info[0].label;
                    const labelInfo = typeof label === 'string' ? JSON.parse(label) : label;

                    if (labelInfo.title_text) {
                        let bgColor = labelInfo.bg_default_color || '#01A0CB';
                        let textColor = labelInfo.title_default_color || '#EEFBFF';
                        let titleText = labelInfo.title_text;
                        if (titleText == '我') {
                            bgColor = 'var(--text-tertiary)';
                            textColor = 'var(--bg-card)';
