                    console.error("解析标签信息失败:", e);
                    const zhTitle = user_info.user_tag.user_title_info[0]?.zh_title || '标签';
                    userTagHtml += `<span class="user-title-tag">${zhTitle}</span>`;
                }
            }

            const commentText = reduceEmojiImg(content?.text || '');
            const imagesHtml = getImagesHtml(content?.image_data_list);
            const videosHtml = getVideosHtml(comment?.expand?.video_info);

            html += `
            <li class="comment-item main-comment" cid="${comment.comment_id}">
                <div class="floor-badge">#${floor}</div>
                <div class="user-info">
                    <img class="user-avatar" src="${userAvatar}" alt="${userName}的头像">
                    <div class="user-meta">
                        <div class="user-name-tag-container">
