                <div class="comment-content">${commentText}</div>
                ${imagesHtml ? `<div class="comment-images">${imagesHtml}</div>` : ''}
                ${videosHtml ? videosHtml : ''}
                <div class="comment-footer">
                    <span class="comment-floor">${floor}楼</span>
                    <span class="comment-time text-truncate">${fmtDate(create_timestamp * 1000)}</span>
                    <div class="comment-replies">
                        <span class="reply-icon"></span>
                        <span class="reply-count">${reply_count || 0}</span>
                    </div>
                    <div class="comment-likes">
                        <span class="like-icon"></span>
                        <span class="like-count">${digg_count || 0}</span>
                    </div>
                </div>
                ${reply_count > 0 && comment?.comment_id ? `
                <div class="reply-section">
                    <button class="more-replies-btn" 
                            data-params="'${bookId}','${chapterId}','${author}','${comment.comment_id}',0" 
                            data-type="1" 
