                </div>` : ''}
            </li>`;
        });

        if (result.data?.common_list_info?.has_more) {
            html += `
            <div id="next_page" class="load-more" 
                 data-params="'${bookId}','${chapterId}','${author}','${paragraphId}','${version}',${page + 1}" 
                 data-type="1">
                <div class="loader-basic"></div>
            </div>`;
        }
    } else if (page === 0) {
        html = `
        <li class="comment-item" style="text-align: center; padding: var(--spacing-xl); color: var(--text-tertiary); background: linear-gradient(135deg, var(--bg-tertiary), var(--bg-secondary));">
