                }

                userBadges += '</span>';
            }

            let userTagHtml = '';

            if (user_info?.user_sticker?.sticker?.url) {
                userTagHtml += `<img class="user-tag" src="${user_info.user_sticker.sticker.url}" alt="用户标签">`;
            }

            if (userName == java.base64Decode(author)) {
                let bgColor = 'var(--text-tertiary)';
                let textColor = 'var(--bg-card)';

                userTagHtml += `
                <span class="user-title-tag" 
                    style="background-color: ${bgColor}; 
                    color: ${textColor};">
                    作者
                </span>`;
            }

            if (item.has_author_digg) {
                let bgColor = 'var(--text-tertiary)';
                let textColor = 'var(--bg-card)';

                userTagHtml += `
                <span class="user-title-tag" 
                    style="background-color: ${bgColor}; 
                    color: ${textColor};">
                    作者赞过
                </span>`;
            }

            if (user_info?.user_title_infos?.[0]?.label_info) {
                try {
                    const labelInfo = user_info.user_title_infos[0].label_info;

                    if (labelInfo.title_text) {
                        let bgColor = labelInfo.bg_default_color || '#01A0CB';
                        let textColor = labelInfo.title_default_color || '#EEFBFF';
                        let titleText = labelInfo.title_text;
                        if (titleText == '我') {
                            bgColor = 'var(--text-tertiary)';
                            textColor = 'var(--bg-card)';
                        }

                        userTagHtml += `
                        <span class="user-title-tag" 
                            style="background-color: ${bgColor}; 
                            color: ${textColor};">
                            ${titleText}
                        </span>`;
                    }
                } catch (e) {
                    console.error("解析标签信息失败:", e);
                    const zhTitle = user_info.user_tag.user_title_info[0]?.zh_title || '标签';
                    userTagHtml += `<span class="user-title-tag">${zhTitle}</span>`;
                }
            }

            const replyText = reduceEmojiImg(text || '');
            const imagesHtml = getImagesHtml(item);

            html += `<li class="comment-item nested-reply-item" cid="${reply_id}">
                <div class="user-info">
                    <img class="user-avatar small" src="${userAvatar}" alt="${userName}的头像">
                    <div class="user-meta">
                        <div class="user-name-tag-container">
                            <span class="user-name">${userName}</span>
                            ${userBadges}
                            ${userTagHtml}
                        </div>
                    </div>
                </div>

                <div class="comment-content">`;

            if (reply_to_user_name) {
                html += `<div class="reply-to-info">回复 @${reply_to_user_name}</div>`;
            }

            html += `${replyText}</div>`;

            if (imagesHtml) {
                html += `<div class="comment-images">${imagesHtml}</div>`;
            }

            html += `<div class="comment-footer">
                    <span class="comment-time">${fmtDate(create_timestamp * 1000)}</span>
                    <div class="comment-replies">
                        <span class="reply-icon"></span>
                        <span class="reply-count">${reply_cnt}</span>
                    </div>
                    <div class="comment-likes">
                        <span class="like-icon"></span>
                        <span class="like-count">${digg_count || 0}</span>
                    </div>
                </div>`;

            if (reply_cnt > 0) {
                html += `<div class="reply-section">
                    <button class="more-nested-replies-btn" 
                            data-params="'${bookId}','${chapterId}','${author}','${reply_id}',0" 
                            data-type="4" 
                            onclick="moreNestedReply(this)">
                        展开${reply_cnt}条回复
                    </button>
                </div>`;
            }

            html += `</li>`;
        });

        if (data?.has_more) {
            html += `<button class="more-nested-replies-btn" 
                    data-params="'${bookId}','${chapterId}','${author}','${parentCommentId}',${page + 1}" 
                    data-type="4" 
                    onclick="moreNestedReply(this)">
                展开更多回复
            </button>`;
        }
    }

    return html;
}



// 正文处理
function getContent(book_id, item_id, item_name, version, content) {
    const { java, cache, book, chapter } = this;
    let ck = cache.get('fqck') || '';

    if (book.type == 4 || book.type == 32 || book.type == 64 || book.type == 1088 || version == undefined) {
        return content;
    }

    let res = java.ajax(this.xGod(
        "API669",
        `/reading/ugc/idea/list/v/?`,
        [
            "book_id=" + book_id,
            "item_id=" + item_id,
            "item_version=" + version
        ].join("&"),
        null,
        ck
    ));

    let separator = "\n";

    if (/<\/p>/.test(content)) {
    	content = String(content)
.replace(/\s*<p>\s*<\/p>\s*|\s*<\/p>\s*<p>\s*(?=<)/g,"")
.replace(/<p[^>]+(?!\sidx=)[^>]+>(<.*?>)<\/p>/g, "$1")
.replace(/\s*<p[^>]+(?!\sidx=)[^>]+>\s*<\/p>\s*|\s*$/g, "");
        separator = "</p>";
    }

    content = this.getContentImg(content)

    let paragraphs = content.split(separator);
    try {
        chapter.putVariable('fqContent', JSON.stringify(paragraphs));
        chapter.putImgUrl('');
    } catch {}

    if (this.Get("dp") !== 1 && this.Get("sp") !== 1 && this.Get("zp") !== 1) {
        return content;
    }

    try {
        let ideas = JSON.parse(res).data.idea_data;

        for (let i in paragraphs) {
            if (this.Get("dp") == 1 || this.Get("sp") == 1) {
                let ideaItem = ideas[i.toString()];
                let num = ideaItem?.idea_count || 0;
                let type = 0;
                if (ideaItem?.self_commented) type = 1;
                if (ideaItem?.author_commented) type = 2;
                paragraphs[i] = paragraphs[i].replace(/\s*<[^>]+>\s*/g,'') == "" ? "" : (paragraphs[i] + ((this.Get("dp") == 1 && (this.Get("dp_0") == 1 || (this.Get("dp_0") != 1 && num > 0))) ? `${this.getDPImage(i, num, type)}` : "") + (this.Get("sp") == 1 && ideaItem?.show_out_comments && ideaItem?.show_out_comments.length > 0 ? `${this.getSPImage(java.base64Encode(ideaItem?.show_out_comments[0]?.text))}` : ""));
            }
        }
    } catch(e) {
        java.log(e + "\n段评神评匹配失败");
        return content;
    }
    return paragraphs.join(separator).replace(/(<\/p>\s*)+/g, "</p>") + (this.Get("zp") == 1 ? `${this.getZPImage(book_id, item_id)}` : "");
}



// 原文图片
function getContentImg(content) {
    const { java, cache, book, chapter } = this;

    var imgRegex = /<img\s+([^>]+?)\/?>/g;

    return content.replace(imgRegex, (match, attributes) => {
        const widthMatch = attributes.match(/\bimg-width="(\d+)"/);
        if (!widthMatch) {
            return match;
        }

        const width = parseInt(widthMatch[1], 10);
        if (width >= 80) {
            return match;
        }

        const srcMatch = attributes.match(/\bsrc="([^"]+)"/);
        if (!srcMatch) {
            return match;
        }

        const src = srcMatch[1];

        return `<img src="${src},{\"style\":\"text\"}"/>`;
    });
}



// 章评SVG
function getZPImage(book_id, item_id){
    const { java, cache, book, chapter } = this;

    let count = this.getChapterReviewByPage(book_id, item_id, book.author, 1, 1);
    count = parseInt(count) || 0;

    return `\n<img src="http://,{"style":"full","js":"getZPSvg(${count},${Date.now()})","click":"getZP(${count})"}"/>`;
}

function getZP(count) {
    const { java, cache, book, chapter } = this;

    let bookId = java.hexDecodeToString(java.ajax(book.tocUrl));
    let chapterId = java.hexDecodeToString(java.ajax(chapter.url));
    let itemName = String(chapter.title).replace(/%20/g,' ');
    java.showBrowser("", `${this.getChapterReview(bookId, chapterId, itemName, count)}`, "window.run=run;window.java=java;", `{
        "expandedCornersRadius": 15,
        "backgroundDimAmount":0.7,
        "heightPercentage": 0.9
    }`);
}

function getZPSvg(count) {
    const { java, cache, book, chapter } = this;

    // 获取颜色配置
    let colors = this.getColorConfig();
    let textColor = colors[3];
    let borderColor = colors[4];
    let svgWidth = colors[5];

    let titleFontSize = 60;
    let countFontSize = 50;
    let padding = 25;

    // 构建显示文本
    let leftText = "本章讨论";
    let rightText = `${count}条讨论 >`;

    // 计算文本宽度
    function calculateTextWidth(text, fontSize) {
        let chineseCount = (text.match(/[^\x00-\xff]/g) || []).length;
        let otherCount = text.length - chineseCount;
        return chineseCount * fontSize + otherCount * fontSize * 0.6;
    }

    let leftTextWidth = calculateTextWidth(leftText, titleFontSize);
    let rightTextWidth = calculateTextWidth(rightText, countFontSize);

    let textHeight = Math.max(titleFontSize, countFontSize);
    let topMargin = 25;
    let bottomMargin = 25;
    let svgHeight = textHeight + padding * 2 + topMargin + bottomMargin;

    // 构建SVG
    let svg = `<svg width="${svgWidth}" height="${svgHeight}" viewBox="0 0 ${svgWidth} ${svgHeight}" xmlns="http://www.w3.org/2000/svg">`;

    let borderRadius = 12;

    // 文本框整体路径
    svg += `
    <!-- 文本框整体路径 -->
    <path d="M 2 ${borderRadius + topMargin}
             Q 2 ${topMargin}, ${borderRadius} ${topMargin}
             H ${svgWidth - borderRadius}
             Q ${svgWidth - 2} ${topMargin}, ${svgWidth - 2} ${borderRadius + topMargin}
             V ${svgHeight - borderRadius - bottomMargin}
             Q ${svgWidth - 2} ${svgHeight - bottomMargin}, ${svgWidth - borderRadius} ${svgHeight - bottomMargin}
             H ${borderRadius}
             Q 2 ${svgHeight - bottomMargin}, 2 ${svgHeight - borderRadius - bottomMargin}
             V ${borderRadius + topMargin} Z"
          fill="${borderColor}" fill-opacity="0.1" stroke="${borderColor}" stroke-opacity="0.3" stroke-width="2"/>`;

    // 添加左侧"本章讨论"文本
    let leftTextX = 25;
    let leftTextY = padding + topMargin + textHeight / 2 + 22;

    svg += `<text x="${leftTextX}" y="${leftTextY}" font-family="Arial, sans-serif" font-size="${titleFontSize}" font-weight="bold" fill="${textColor}" text-anchor="start" dominant-baseline="middle">${leftText}</text>`;

    // 添加右侧"X条讨论 >"文本
    let rightTextX = svgWidth - 25;
    let rightTextY = padding + topMargin + textHeight / 2 + 18;

    svg += `<text x="${rightTextX}" y="${rightTextY}" font-family="Arial, sans-serif" font-size="${countFontSize}" fill="${textColor}" text-anchor="end" dominant-baseline="middle">${rightText}</text>`;

    svg += `</svg>`;

    return "data:image/svg+xml;base64," + java.base64Encode(svg);
}

function getChapterReview(bookId, itemId, itemName, num) {
    const { java, cache, book, chapter } = this;

    let h3 = `
        <h3 id="h3">
            <span class="content">本章讨论</span>
            <span class="count" id="count">共 ${num} 条</span>
        </h3>
    `;

    let paramsHtml = `<div data-type="2" data-author="${book.author}" class="hidden" id="params">'${bookId}','${itemId}','${java.base64Encode(book.author)}',0</div>`;
    return this.getHtml().replace("$1", itemName).replace("$2", paramsHtml).replace('<h3 id="h3"></h3>', h3);
