    return this.getHtml().replace("$1", itemName).replace("$2", paramsHtml).replace('<h3 id="h3"></h3>', h3);
}



// 神评SVG
function getSPImage(text){
    const { java, cache, book, chapter } = this;

    return `\n<img src="http://,{"style":"full","js":"getSPSvg('${text}',${Date.now()})"}"/>`;
}

function getSPSvg(text) {
    const { java, cache, book, chapter } = this;

    // 获取颜色配置
    let colors = this.getColorConfig();
    let spColor = colors[2];
    let textColor = colors[3];
    let borderColor = colors[4];
    let svgWidth = colors[5];

    text = B2E(String(java.base64Decode(text)));
    let textFontSize = 50;
    let labelFontSize = 45;
    let textLineHeight = 65;
    let padding = 25;
    let labelWidth = textFontSize * 2;

    // 计算可用宽度
    let availableWidth = svgWidth - 33;
    let firstLineAvailableWidth = availableWidth - labelWidth - 10;

    // 表情符号检测函数
    function isEmoji(char, nextChar = '') {
        let code = char.charCodeAt(0);

        // UTF-16 代理对（最常见的表情符号）
        if (code >= 0xD800 && code <= 0xDBFF && nextChar && 
            nextChar.charCodeAt(0) >= 0xDC00 && nextChar.charCodeAt(0) <= 0xDFFF) {
            return true;
        }

        // 扩展的表情符号 Unicode 范围
        if ((code >= 0x1F600 && code <= 0x1F64F) || // 表情符号
            (code >= 0x1F300 && code <= 0x1F5FF) || // 符号和象形文字
            (code >= 0x1F680 && code <= 0x1F6FF) || // 交通和地图符号
            (code >= 0x1F900 && code <= 0x1F9FF) || // 补充符号和象形文字
            (code >= 0x2600 && code <= 0x26FF) ||   // 杂项符号
            (code >= 0x2700 && code <= 0x27BF) ||   // 装饰符号
            (code >= 0x1F1E6 && code <= 0x1F1FF)) { // 区域指示符号
            return true;
        }

        return false;
    }

    // 检查是否是 ZWJ 连接符 (U+200D)
    function isZWJ(char) {
        return char.charCodeAt(0) === 0x200D;
    }

    // 检查是否是变异选择器 (U+FE0F)
    function isVariationSelector(char) {
        return char.charCodeAt(0) === 0xFE0F;
    }

    // 获取字符宽度和总间距的函数
    function getCharInfo(char, nextChar = '', isEmojiSequence = false) {
        // 检查是否是换行符（不显示但触发换行）
        if (char === '\n' || char === '\r') {
            return { width: 0, totalSpacing: 0, isNewline: true };
        }

        // 检查是否是表情符号
        if (isEmojiSequence || (nextChar !== '' && isEmoji(char, nextChar))) {
            return { width: 58, totalSpacing: 15, isNewline: false };
        }

        // 检查是否是中文汉字
        if (char >= '\u4e00' && char <= '\u9fff') {
            return { width: 40, totalSpacing: 15, isNewline: false };
        }

        // 检查是否是宽字符
        if (/[ABCDEFGHKLNOPQRSTUVXYZ@%&]/.test(char)) {
            return { width: 25, totalSpacing: 8, isNewline: false };
        }

        // 检查是否是中等字符
        if (/[abcdeghknopquvxyz023456789  ~#$^+=<>]/.test(char)) {
            return { width: 20, totalSpacing: 8, isNewline: false };
        }

        // 检查是否是窄字符
        if (/[fJtr1()\[\]{}"]/.test(char)) {
            return { width: 6, totalSpacing: 8, isNewline: false };
        }

        // 检查是否是极窄字符
        if (/[\s,.';`:!iljI|]/.test(char)) {
            return { width: 3, totalSpacing: 8, isNewline: false };
        }

        // 单独定义字符宽度
        if (/[MW]/.test(char)) {
            return { width: 35, totalSpacing: 8, isNewline: false };
        }
        if (/[mw]/.test(char)) {
            return { width: 30, totalSpacing: 8, isNewline: false };
        }
        if (/[s?*_\-\\/]/.test(char)) {
            return { width: 14, totalSpacing: 8, isNewline: false };
        }

        // 其他字符（如中文标点等）使用中文宽度和间距
        return { width: 40, totalSpacing: 15, isNewline: false };
    }

    // 检测单个组合表情符号
    function detectSingleEmojiSequence(text, startIndex) {
        let i = startIndex;
        let sequence = '';
        let hasEmojiStart = false;

        let currentChar = text[i];
        let nextChar = i < text.length - 1 ? text[i + 1] : '';

        if (!isEmoji(currentChar, nextChar)) {
            return null;
        }

        hasEmojiStart = true;

        if (currentChar.charCodeAt(0) >= 0xD800 && currentChar.charCodeAt(0) <= 0xDBFF && nextChar) {
            sequence += currentChar + nextChar;
            i += 2;
        } else {
            sequence += currentChar;
            i += 1;
        }

        while (i < text.length) {
            currentChar = text[i];
            nextChar = i < text.length - 1 ? text[i + 1] : '';

            if (isZWJ(currentChar)) {
                sequence += currentChar;
                i += 1;

                if (i < text.length) {
                    currentChar = text[i];
                    nextChar = i < text.length - 1 ? text[i + 1] : '';

                    if (isEmoji(currentChar, nextChar)) {
                        if (currentChar.charCodeAt(0) >= 0xD800 && currentChar.charCodeAt(0) <= 0xDBFF && nextChar) {
                            sequence += currentChar + nextChar;
                            i += 2;
                        } else {
                            sequence += currentChar;
                            i += 1;
                        }
                    } else {
                        break;
                    }
                }
            } else if (isVariationSelector(currentChar)) {
                sequence += currentChar;
                i += 1;
            } else if (isEmoji(currentChar, nextChar)) {
                break;
            } else {
                break;
            }
        }

        return hasEmojiStart ? {
            content: sequence,
            length: sequence.length
        } : null;
    }

    // 处理字符序列
    function processCharacter(text, startIndex) {
        let currentChar = text[startIndex];
        let nextChar = startIndex < text.length - 1 ? text[startIndex + 1] : '';

        if (currentChar === '\n' || currentChar === '\r') {
            return {
                charContent: '',
                charW: 0,
                totalSpacing: 0,
                advance: (currentChar === '\r' && nextChar === '\n') ? 2 : 1,
                isNewline: true,
                isEmoji: false
            };
        }

        let emojiSequence = detectSingleEmojiSequence(text, startIndex);
        if (emojiSequence) {
            let charInfo = getCharInfo(currentChar, nextChar, true);
            return {
                charContent: emojiSequence.content,
                charW: charInfo.width,
                totalSpacing: charInfo.totalSpacing,
                advance: emojiSequence.length,
                isNewline: false,
                isEmoji: true
            };
        }

        if (isEmoji(currentChar, nextChar)) {
            if (currentChar.charCodeAt(0) >= 0xD800 && currentChar.charCodeAt(0) <= 0xDBFF && nextChar) {
                let charContent = currentChar + nextChar;
                let charInfo = getCharInfo(currentChar, nextChar, false);
                return {
                    charContent: charContent,
                    charW: charInfo.width,
                    totalSpacing: charInfo.totalSpacing,
                    advance: 2,
                    isNewline: false,
                    isEmoji: true
                };
            } else {
                let charInfo = getCharInfo(currentChar, nextChar, false);
                return {
                    charContent: currentChar,
                    charW: charInfo.width,
                    totalSpacing: charInfo.totalSpacing,
                    advance: 1,
                    isNewline: false,
                    isEmoji: true
                };
            }
        }

        let charInfo = getCharInfo(currentChar, '', false);
        return {
            charContent: currentChar,
            charW: charInfo.width,
            totalSpacing: charInfo.totalSpacing,
            advance: 1,
            isNewline: false,
            isEmoji: false
        };
    }

    // 计算字符的实际显示宽度
    function getCharDisplayWidth(charData) {
        return charData.charW + charData.totalSpacing;
    }

    // 换行算法
    let lines = [];
    let lineTypes = [];
    let lineJustified = [];
    let lineExtraSpacing = [];
    let nextLineIndented = [];
    let currentLine = '';
    let currentLineContent = [];
    let currentLineDisplayWidth = 0;
    let isFirstLine = true;
    let i = 0;

    while (i < text.length) {
        let result = processCharacter(text, i);

        let maxWidth = isFirstLine ? firstLineAvailableWidth : availableWidth;

        if (result.isNewline) {
            if (currentLine !== '') {
                lines.push(currentLine);
                lineTypes.push(isFirstLine ? 'first' : 'manual');
                lineJustified.push(false);
                lineExtraSpacing.push(0);
                nextLineIndented.push(true);
            }
            currentLine = '';
            currentLineContent = [];
            currentLineDisplayWidth = 0;
            isFirstLine = true;
            i += result.advance;
            continue;
        }

        let charDisplayWidth = getCharDisplayWidth(result);

        if (currentLine === '') {
            currentLine = result.charContent;
            currentLineContent = [result];
            currentLineDisplayWidth = charDisplayWidth;
            i += result.advance;
            continue;
        }

        let newDisplayWidth = currentLineDisplayWidth + charDisplayWidth;

        if (newDisplayWidth > maxWidth) {
            let totalCharWidth = currentLineContent.reduce((sum, char) => sum + char.charW, 0);
            let totalSpacing = currentLineContent.reduce((sum, char) => sum + char.totalSpacing, 0);

            let remainingWidth = maxWidth - (totalCharWidth + totalSpacing);

            lines.push(currentLine);

            if (isFirstLine) {
                lineTypes.push('first');
                lineJustified.push(true);
            } else {
                lineTypes.push('middle');
                lineJustified.push(true);
            }

            let totalChars = currentLineContent.length;
            let extraSpacing = 0;
            if (totalChars > 1) {
                extraSpacing = Math.max(0, remainingWidth) / (totalChars - 1);
            }
            lineExtraSpacing.push(extraSpacing);
            nextLineIndented.push(false);

            currentLine = result.charContent;
            currentLineContent = [result];
            currentLineDisplayWidth = charDisplayWidth;
            isFirstLine = false;
        } else {
            currentLine += result.charContent;
            currentLineContent.push(result);
            currentLineDisplayWidth = newDisplayWidth;
        }

        i += result.advance;
    }

    // 处理最后一行
    if (currentLine !== '') {
        lines.push(currentLine);

        if (isFirstLine) {
            lineTypes.push('first');
            lineJustified.push(false);
        } else {
            lineTypes.push('last');
            lineJustified.push(false);
        }

        lineExtraSpacing.push(0);
        nextLineIndented.push(false);
    }

    let textHeight = lines.length * textLineHeight;
    let topMargin = 15;
    let bottomMargin = 25;
    let svgHeight = textHeight + padding * 2 + topMargin + bottomMargin;

    let svg = `<svg width="${svgWidth}" height="${svgHeight}" viewBox="0 0 ${svgWidth} ${svgHeight}" xmlns="http://www.w3.org/2000/svg">`;

    let borderRadius = 12;
    let triangleSize = 15;

    svg += `
    <!-- 对话框整体路径 -->
    <path d="M 2 ${borderRadius + topMargin}
             Q 2 ${topMargin}, ${borderRadius} ${topMargin}
             H ${svgWidth - 120}
             L ${svgWidth - 100} ${topMargin - triangleSize}
             L ${svgWidth - 80} ${topMargin}
             H ${svgWidth - borderRadius}
             Q ${svgWidth - 2} ${topMargin}, ${svgWidth - 2} ${borderRadius + topMargin}
             V ${svgHeight - borderRadius - bottomMargin}
             Q ${svgWidth - 2} ${svgHeight - bottomMargin}, ${svgWidth - borderRadius} ${svgHeight - bottomMargin}
             H ${borderRadius}
             Q 2 ${svgHeight - bottomMargin}, 2 ${svgHeight - borderRadius - bottomMargin}
             V ${borderRadius + topMargin} Z"
          fill="${borderColor}" fill-opacity="0.1" stroke="${borderColor}" stroke-opacity="0.3" stroke-width="2"/>

    <!-- 神评标签 -->
    <defs>
        <mask id="shenpingMask">
            <rect width="100%" height="100%" fill="white"/>
            <text x="${20 + labelWidth/2}" y="${padding + topMargin + (textFontSize + 10)/2 + 19}" font-family="Arial" font-weight="bold" text-anchor="middle" dominant-baseline="middle" font-size="${labelFontSize}" fill="black">神评</text>
        </mask>
    </defs>
    <rect x="20" y="${padding + topMargin + 2}" width="${labelWidth}" height="${textFontSize + 10}" rx="10" ry="10" fill="${spColor}" mask="url(#shenpingMask)"/>`;

    // 渲染文本行
    function renderTextLine(line, startX, lineIndex, extraSpacing, justified) {
        let svgText = '';
        let currentX = startX;
        let j = 0;
        let charIndex = 0;

        // 统计本行字符数
        let totalChars = 0;
        let tempJ = 0;
        while (tempJ < line.length) {
            let tempResult = processCharacter(line, tempJ);
            if (!tempResult.isNewline) {
                totalChars++;
            }
            tempJ += tempResult.advance;
        }

        let firstEmoji = true;

        while (j < line.length) {
            let result = processCharacter(line, j);

            if (result.isNewline) {
                j += result.advance;
                continue;
            }

            // 计算间距            
            let beforeSpacing = 0;
            let afterSpacing = 0;

            if (charIndex > 0) {
                beforeSpacing = result.totalSpacing / 2;

                // 两边对齐添加额外间距
                if (justified && extraSpacing > 0) {
                    beforeSpacing += extraSpacing;
                }
            }

            if (charIndex < totalChars - 1) {
                afterSpacing = result.totalSpacing / 2;
            }

            currentX += beforeSpacing;

            let xOffset = result.isEmoji ? currentX + 3 : currentX;

            if (result.isEmoji) {
                if (firstEmoji) {
                    svgText += `<tspan x="${xOffset}" dy="-3">${result.charContent}</tspan>`;
                    firstEmoji = false;
                } else {
                    svgText += `<tspan x="${xOffset}" dy="0">${result.charContent}</tspan>`;
                }
            } else {
                svgText += `<tspan x="${xOffset}">${result.charContent}</tspan>`;
            }

            currentX += result.charW + afterSpacing;

            j += result.advance;
            charIndex++;
        }

        return svgText;
    }

    let lineIndents = new Array(lines.length).fill(false);

    lineIndents[0] = true;

    for (let idx = 1; idx < lines.length; idx++) {
        lineIndents[idx] = nextLineIndented[idx - 1];
    }

    // 基线对齐
    svg += `<g font-family="Arial, sans-serif" font-size="${textFontSize}" fill="${textColor}" text-anchor="start" dominant-baseline="alphabetic">`;

    lines.forEach((line, index) => {
        let y = padding + topMargin + (index * textLineHeight) + textFontSize;

        let startX;
        if (lineIndents[index]) {
            startX = 19 + labelWidth + 10;
        } else {
            startX = 19;
        }

        svg += `<text y="${y}">`;
        svg += renderTextLine(line, startX, index, lineExtraSpacing[index], lineJustified[index]);
        svg += `</text>`;
    });

    svg += `</g></svg>`;

    return "data:image/svg+xml;base64," + java.base64Encode(svg);
}



