function Match(result) {
    const matches = result.match(/<[^>]*>([^<]*)<\/[^>]*>/g); 
    if (!matches) return result;
    const textParts = matches.map(match => {
        return match.replace(/<[^>]*>/g, '');
    });
    return textParts.join('');
}
Match(result);

