var u_Index = Get("ml");

var u_Types = ['API', 'WEB', 'TOU'];
var v_Index = [];
var v_Names = [];
var c_Array = [];

function b64Url(item_id, item_name) {
    return `data:item_id;base64,${java.base64Encode(item_id)},{"type":"Z_xh","info":"${book_id}#${item_id}"}`;
}

function push_a(a, b, c, d) {
    c_Array.push({
        "ChapterName": a || "",
        "isVolume": b || false,
        "chapterUrl": c ? b64Url(c, a) : "",
        "ChapterInfo": (d || "").replace(/第.卷：默认 \|/g, "").trim(),
    });
}

function push_b(list) {
    for (let i = 0; i < list.length; i++) {
        let c = list[i];
        let c_name = c.volume_name || "第一卷：默认";
        let c_time = c.first_pass_time ? java.timeFormatUTC(c.first_pass_time * 1000, 'yyyy-MM-dd HH:mm:ss', 12) : "";
        let c_title = c.first_pass_time ? (i == list.length - 1 ? c.title + " • " + c_time : c.title) : c.title;
        let c_word = c.chapter_word_number ? c.chapter_word_number + "字" : "";
        let c_info = [c_name, c_time, c_word];
        let v_name = v_Names[v_Names.length - 1];
        if (v_name != c_name) {
            // java.log(c_name);
            v_Index.push(c_Array.length);
            v_Names.push(c_name);
            push_a(c_name, true);
        }
        push_a(c_title, false, c.item_id, c_info.join(" | ").replace(/\s\|\s$/g,""));
    }
}

function tocUrl(utype, params, run) {
    let url = `${Get("urls")[1]}/api/novel/book/directory/${utype}/v1/?aid=1967&${params}`;
    if (run) return url;
    return JSON.parse(java.ajax(url)).data;
}

function push_c(arr) {
    let newArr = [];
    let newData = [];
    for (let i = 0; i < arr.length;) {
        let item_ids = arr.slice(i, (i += 100));
        newArr.push(tocUrl("detail", "item_ids=" + item_ids, true));
    }
    java.ajaxAll(newArr).map(Get => {
        let response = String(Get.body()).replace(/\\/g, "\\")
            .replace(/\\+([\u4e00-\u9fa5])/g, "$1")
            .replace(/\\([^fnrt"'])/g, "$1");
            newData = newData.concat(JSON.parse(response).data||[{}]);
    });
    return push_b(newData);
}


switch (String(u_Types[u_Index])) {
        //  app接口  ##卷名&时间&字数
